arguments.file_text:
@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var claim in context.User.Claims.Where(c => c.Type == System.Security.Claims.ClaimTypes.Role))
            {
                <li>@claim.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the editor page. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<p>Welcome, @context.User.Identity?.Name! This page is accessible to any authenticated user.</p>

@code {
    [CascadingParameter]
    private Task<AuthenticationState>? AuthState { get; set; }

    private AuthenticationState context = new(new System.Security.Claims.ClaimsPrincipal());

    protected override async Task OnInitializedAsync()
    {
        if (AuthState is not null)
        {
            context = await AuthState;
        }
    }
}

